INSERT IGNORE INTO pages (slug, title, type) VALUES ('apprentissage-continu', 'Apprentissage continu', 'competence');
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'header_title', 'h1', 'Apprentissage continu', 'hero', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'header_breadcrumb', 'label', 'Accueil / Compétences', 'hero', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'definition_title', 'h2', 'DÉFINITION', 'definition', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'definition_p1', 'paragraph', 'L''apprentissage continu est, à mon avis, à la fois une compétence essentielle en développement et la raison pour laquelle ce domaine est si passionnant.', 'definition', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'definition_p2', 'paragraph', 'L''apprentissage continu représente notre capacité à apprendre, voire à apprendre à apprendre, en réalisant des projets tests sur des technologies que nous ne connaissons pas, afin d''acquérir de nouveaux paradigmes de programmation, concepts et langages, ainsi que de nouvelles connaissances et compétences.', 'definition', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'definition_p3', 'paragraph', 'Selon un TIL (Today I Learned) rédigé par Julien Cavaillès, nous pouvons décomposer cette compétence d''apprentissage continu en quatre étapes.', 'definition', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'definition_phases', 'callout', 'Les 4 phases de l''apprentissage continu\nSocialisation :: L''échange au sein d''une communauté de développeurs pour partager des savoirs, des intuitions et du savoir-faire implicite.\nExternalisation :: Notre capacité à vulgariser, verbaliser et transmettre à l''écrit et à l''oral les connaissances et compétences acquises durant notre veille technologique. L''écriture permet de formaliser une idée, c''est une étape clé de l''apprentissage continu.\nCombinaison :: C''est l''étape de consolidation des différents retours dans un guide interne. C''est un assemblage de connaissances existantes pour en créer une vision commune.\nInternalisation :: C''est l''application de la connaissance, le savoir lu ou vu en tutoriel appliqués dans des projets concrets.', 'definition', 5);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section1_number', 'number', '1', 'preuves', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section1_title', 'h2', 'Éléments de preuve', 'preuves', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section1_p1', 'paragraph', 'Notre capacité à apprendre en continu est clairement l''un des soft skills enseignés dans les modules de l''ISCOD. En suivant les cours de Docker et de Kubernetes, j''ai pu dockeriser toutes les stacks technologiques chez Coliback.\n\nCette mise en place n''a pas été simple au début, car je n''avais aucun référent compétent en Docker. J''apprenais en appliquant de manière expérimentale les connaissances acquises. Les échanges avec mon Learning Coach, qui était experte en Docker, m''ont beaucoup aidé à m''améliorer.', 'preuves', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section1_p2', 'paragraph', 'À la fin de mon Bac+3, j''ai obtenu un poste de développeur AngularJS dans des technologies que je ne maîtrisais pas du tout. J''ai donc lu la documentation technique et suivi des tutoriels pour développer une application en AngularJS, ce qui m''a permis d''acquérir les bases fondamentales nécessaires à ce poste.\n\nChez Coliback, les projets sur lesquels nous travaillons reposent sur des stacks technologiques que je ne maîtrisais pas au début. Il était donc nécessaire de lire la documentation et d''utiliser l''IA comme support d''apprentissage pour comprendre les concepts et paradigmes essentiels à la création de solutions durables.\n\nPar exemple, dans un projet, j''ai développé un back-office avec Directus et j''ai dû intégrer des flux de données lors de la modification d''une table. Il était crucial de comprendre comment s''articulent les bases de données dans Directus, ce qu''est un flux et comment le configurer pour réaliser ce projet, tout en tenant compte que l''IA n''est pas intégrée à Directus.\n\nDans le développement du projet Coliback Premium, nous savions qu''il fallait passer par l''API Shopify, mais je n''avais jamais utilisé cette API auparavant. Cela a été un véritable défi, car j''ai dû lire la documentation et utiliser l''IA intelligemment pour développer un logiciel fonctionnant sur des boutiques Shopify.\n\nEn intégration web, j''ai dû intégrer une maquette personnalisée dans Elementor. Pour cela, j''ai consulté de nombreux tutoriels, articles, documentations et vidéos en ligne pour comprendre la logique sous-jacente de WordPress et intégrer des maquettes durables.', 'preuves', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section2_number', 'number', '2', 'evolution', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section2_title', 'h2', 'Évolution', 'evolution', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section2_p1', 'paragraph', 'Je suis conscient que le titre de mon poste en tant que développeur pourrait évoluer au cours de ma carrière, et cela ne sera possible qu''en développant une méthodologie de travail personnelle permettant de suivre l''évolution de cette compétence dans le temps.', 'evolution', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section3_number', 'number', '3', 'autocritique', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section3_title', 'h2', 'Autocritique', 'autocritique', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'section3_p1', 'paragraph', 'L''apprentissage continu est une compétence fondamentale qui me passionne dans le domaine de l''informatique, car il représente un défi perpétuel de compréhension qui rend ce secteur captivant.\n\nCependant, bien que l''apprentissage continu soit inhérent au métier de programmeur, il nécessite une bonne capacité à organiser la restitution de ces informations pour les rendre exploitables sur le long terme.', 'autocritique', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('apprentissage-continu', 'projects_title', 'h2', 'Projets', 'projets', 1);
